import java.util.Map;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutionException;
import java.util.concurrent.TimeUnit;

public class McpRedirectRepro {
    private static int oldHits;
    private static int newHits;

    public static void main(String[] args) throws Exception {
        boolean enableRedirects = args.length > 0 && args[0].equals("--follow");
        HttpServer server = HttpServer.create(new InetSocketAddress("127.0.0.1", 0), 0);
        int port = server.getAddress().getPort();
        server.createContext("/old", exchange -> redirect(exchange, "http://127.0.0.1:" + port + "/new"));
        server.createContext("/new", McpRedirectRepro::respondToMcpPost);
        server.start();

        StreamableHttpMcpTransport transport = null;
        try {
            StreamableHttpMcpTransport.Builder builder = StreamableHttpMcpTransport.builder()
                    .url("http://127.0.0.1:" + port + "/old");
            if (enableRedirects) {
                Method followRedirects = builder.getClass().getMethod("followRedirects", HttpClient.Redirect.class);
                followRedirects.invoke(builder, HttpClient.Redirect.NORMAL);
            }
            transport = builder.build();
            transport.start(new McpOperationHandler(
                    new ConcurrentHashMap<Long, CompletableFuture<JsonNode>>(),
                    () -> List.<McpRoot>of(),
                    transport,
                    ignored -> {},
                    () -> {}));

            JsonNode response = transport.initialize(new McpInitializeRequest(1L)).get(5, TimeUnit.SECONDS);
            if (newHits == 0) {
                throw new AssertionError("Redirect target was not reached");
            }
            System.out.println("SUCCESS: redirect followed; response=" + response);
        } catch (ExecutionException e) {
            Throwable root = e.getCause();
            String message = root == null ? e.getMessage() : root.getMessage();
            if (message != null && message.contains("Unexpected status code: 307")) {
                System.out.println("REPRODUCED: redirect was not followed: " + message);
                System.exit(42);
            }
            throw e;
        } finally {
            if (transport != null) {
                transport.close();
            }
            server.stop(0);
            System.out.println("oldHits=" + oldHits + ", newHits=" + newHits);
        }
    }

    private static void redirect(HttpExchange exchange, String location) throws IOException {
        oldHits++;
        exchange.getResponseHeaders().add("Location", location);
        exchange.sendResponseHeaders(307, -1);
        exchange.close();
    }

    private static void respondToMcpPost(HttpExchange exchange) throws IOException {
        newHits++;
        byte[] requestBody = exchange.getRequestBody().readAllBytes();
        String request = new String(requestBody, StandardCharsets.UTF_8);
        String response = request.contains("\"id\":1")
                ? "{\"jsonrpc\":\"2.0\",\"id\":1,\"result\":{}}"
                : "{}";
        exchange.getResponseHeaders().add("Content-Type", "application/json");
        byte[] responseBytes = response.getBytes(StandardCharsets.UTF_8);
        exchange.sendResponseHeaders(200, responseBytes.length);
        try (OutputStream outputStream = exchange.getResponseBody()) {
            outputStream.write(responseBytes);
        }
    }
}
